A,eACA,iBAGF,uBACE,aACA,SACA,eACA,gBAGF,sBACE,gBACA,kBACA,mBACA,gCACA,qCAGF,6BACE,cACA,kBACA,WACA,eACA,gBAGF,2BACE,0BACA,eACA,iBAGF,uBACE,aACA,uBAGF,0BACE,WACA,gBACA,iBACA,aACA,mBACA,+BACA,qCACA,sCACA,2BACA,aACA,mBACA,uBAGF,8BACE,gBACA,WACA,YACA,mBACA,cAGF,qBACE,gBAGF,qBACE,aACA,qCACA,SAGF,qBACE,mBACA,gBACA,+BACA,qCACA,2EAGF,2BACE,2BACA,kCACA,gCAGF,2BACE,aACA,aACA,mBACA,uBACA,aACA,+BAGF,+BACE,gBACA,iBACA,WACA,YACA,mBACA,cAGF,6BACE,aAGF,oBACE,qBACA,mBACA,cACA,eACA,gBACA,qBACA,yBAGF,gCACE,gBACA,WACA,eACA,iBACA,sBAGF,+BACE,SACA,yBACA,eACA,gBAGF,qBACE,gBACA,aACA,mBACA,gCACA,qCAGF,wBACE,gBACA,WACA,eACA,gBACA,sBAGF,uBACE,SACA,yBACA,eACA,gBAGF,0BACE,0CAEE,0BAGF,qBACE,gBAIJ,yBACE,gBACE,oBAGF,wBACE,+BAGF,kGAIE,eAGF,0BACE,gBACA,aAGF,2BACE","sourcesContent":[":root {\n  --bg: #07111f;\n  --bg-soft: #0c1a2d;\n  --card: #10233d;\n  --line: rgba(255,255,255,.08);\n  --text: #eaf2ff;\n  --muted: #9bb0cc;\n  --primary: #27a0ff;\n  --secondary: #14d17f;\n  --accent: #7c5cff;\n  --white: #ffffff;\n  --shadow: 0 20px 60px rgba(0,0,0,.25);\n  --radius: 22px;\n  --max: 1180px;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nbody {\n  margin: 0;\n  font-family: Inter, Arial, sans-serif;\n  background:\n    radial-gradient(circle at top left, rgba(39,160,255,.18), transparent 28%),\n    radial-gradient(circle at top right, rgba(20,209,127,.14), transparent 22%),\n    linear-gradient(180deg, #07111f 0%, #091727 100%);\n  color: var(--text);\n}\n\nimg {\n  max-width: 100%;\n  display: block;\n}\n\na {\n  color: var(--primary);\n  text-decoration: none;\n}\n\n.container {\n  width: min(calc(100% - 2rem), var(--max));\n  margin: 0 auto;\n}\n\n.site-header {\n  position: sticky;\n  top: 0;\n  z-index: 40;\n  backdrop-filter: blur(14px);\n  background: rgba(7,17,31,.75);\n  border-bottom: 1px solid var(--line);\n}\n\n.header-inner {\n  min-height: 82px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 1.5rem;\n}\n\n.brand img {\n  height: 44px;\n  width: auto;\n}\n\n.site-nav {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 1rem;\n}\n\n.site-nav a {\n  color: var(--text);\n  font-size: .95rem;\n  opacity: .92;\n}\n\n.hero-home {\n  padding: 5rem 0 3rem;\n}\n\n.hero-grid,\n.bio-grid,\n.content-grid,\n.contact-grid {\n  display: grid;\n  grid-template-columns: 1.2fr .8fr;\n  gap: 2rem;\n  align-items: center;\n}\n\n.hero-text h1 {\n  font-size: clamp(2.7rem, 7vw, 5rem);\n  line-height: .95;\n  margin: .4rem 0 .8rem;\n}\n\n.hero-text h2 {\n  font-size: clamp(1.15rem, 2vw, 1.8rem);\n  color: var(--muted);\n  font-weight: 600;\n  margin: 0 0 1rem;\n}\n\n.hero-text p,\n.page-description,\n.page-content p,\n.page-content li,\n.post-content {\n  color: var(--muted);\n  line-height: 1.75;\n  font-size: 1.02rem;\n}\n\n.hero-image img,\n.bio-grid img,\n.content-grid img {\n  border-radius: 28px;\n  box-shadow: var(--shadow);\n  border: 1px solid var(--line);\n}\n\n.eyebrow,\n.card-tag {\n  display: inline-flex;\n  align-items: center;\n  gap: .5rem;\n  font-size: .78rem;\n  letter-spacing: .12em;\n  text-transform: uppercase;\n  color: var(--secondary);\n  font-weight: 700;\n}\n\n.hero-actions {\n  display: flex;\n  gap: 1rem;\n  margin-top: 1.5rem;\n  flex-wrap: wrap;\n}\n\n.btn {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 999px;\n  padding: .95rem 1.3rem;\n  font-weight: 700;\n  transition: .2s ease;\n}\n\n.btn-primary {\n  background: linear-gradient(135deg, var(--primary), #4ab8ff);\n  color: #fff;\n}\n\n.btn-secondary {\n  border: 1px solid var(--line);\n  color: var(--text);\n  background: rgba(255,255,255,.03);\n}\n\n.highlight-section,\n.bio-section,\n.posts-section,\n.awards-section,\n.page-hero,\n.page-content {\n  padding: 2.5rem 0;\n}\n\n.cards-3 {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 1.5rem;\n}\n\n.info-card,\n.post-card,\n.contact-card,\n.timeline-item,\n.video-placeholder {\n  background: rgba(255,255,255,.03);\n  border: 1px solid var(--line);\n  border-radius: var(--radius);\n  padding: 1.4rem;\n  box-shadow: var(--shadow);\n}\n\n.info-card h3,\n.post-card h3,\n.page-hero h1,\n.section-heading h2 {\n  margin-top: .6rem;\n  margin-bottom: .7rem;\n}\n\n.section-heading {\n  margin-bottom: 1.5rem;\n}\n\n.project-logo,\n.brand-logo {\n  max-height: 100px;\n  width: auto;\n  object-fit: contain;\n}\n\n.timeline-list {\n  display: grid;\n  gap: 1rem;\n}\n\n.timeline-item {\n  display: flex;\n  justify-content: space-between;\n  gap: 1rem;\n  flex-wrap: wrap;\n}\n\n.post-layout {\n  padding: 3rem 0;\n}\n\n.post-header {\n  margin-bottom: 1.5rem;\n}\n\n.post-cover {\n  border-radius: 24px;\n  margin-bottom: 1.5rem;\n  border: 1px solid var(--line);\n}\n\n.site-footer {\n  margin-top: 4rem;\n  border-top: 1px solid var(--line);\n  background: rgba(0,0,0,.18);\n}\n\n.footer-grid {\n  display: grid;\n  grid-template-columns: 1.2fr .8fr .8fr;\n  gap: 2rem;\n  padding: 2.5rem 0 1rem;\n}\n\n.footer-grid h3,\n.footer-grid h4 {\n  margin-top: 0;\n}\n\n.footer-grid p,\n.footer-grid li,\n.footer-grid a {\n  color: var(--muted);\n}\n\n.footer-bottom {\n  padding: 1rem 0 2rem;\n  color: var(--muted);\n}\n\nul {\n  padding-left: 1.1rem;\n}\n\n@media (max-width: 980px) {\n  .hero-grid,\n  .bio-grid,\n  .content-grid,\n  .contact-grid,\n  .cards-3,\n  .footer-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .site-nav {\n    justify-content: center;\n  }\n\n  .header-inner {\n    flex-direction: column;\n    padding: 1rem 0;\n  }\n}\n\n.logo img {\n  height: 30px;\n  transition: 0.3s;\n}\n\n.logo img:hover {\n  transform: scale(1.05);\n}\n\n.site-logo {\n  display: flex;\n  align-items: center;\n  flex-shrink: 0;\n}\n\n.site-logo img {\n  display: block;\n  height: 180px !important;\n  width: auto !important;\n  max-height: none !important;\n  max-width: none !important;\n}\n\nheader {\n  height: 100px;\n  display: flex;\n  align-items: center;\n}\n\n:root {\n  --bg-dark: #06101d;\