SACA,mBACA,mBAGF,mBACE,gBAGF,gBACE,oBACA,mBACA,gBACA,eACA,mBACA,oBACA,oCACA,+BACA,cACA,eACA,gBACA,qBACA,yBAGF,sBACE,gBACA,WACA,+BACA,iBAGF,qBACE,SACA,0BACA,eACA,gBAGF,gBACE,aACA,eACA,SACA,mBAGF,qBACE,oBACA,mBACA,gBACA,eACA,oBACA,+BACA,qCACA,cACA,eACA,gBAGF,iBACE,aACA,eACA,SAGF,qBACE,aACA,uBAGF,mBACE,WACA,gBACA,iBACA,aACA,mBACA,wFACA,qCACA,uCACA,2BACA,aACA,sBACA,uBAGF,oBACE,oBACA,mBACA,kBACA,gBACA,eACA,oBACA,+BACA,qCACA,cACA,eACA,gBACA,oBACA,yBACA,mBAGF,sBACE,gBACA,WACA,eACA,gBAGF,qBACE,SACA,0BACA,eACA,iBAGF,sBACE,mBAGF,yBACE,gBACA,WACA,eAGF,wBACE,SACA,0BACA,eACA,gBAGF,kBACE,aACA,qCACA,SAGF,kBACE,mBACA,gBACA,+BACA,qCACA,2BACA,2EAGF,wBACE,2BACA,iCACA,sCAGF,oBACE,aACA,+BACA,gBAGF,wBACE,WACA,YACA,iBACA,cACA,+BAGF,gDACE,sBAGF,sBACE,aAGF,eACE,qBACA,mBACA,cACA,eACA,gBACA,qBACA,yBAGF,yBACE,gBACA,WACA,eACA,iBAGF,wBACE,SACA,0BACA,eACA,gBAGF,0BACE,gCAEE,0BAGF,mBACE,gBAIJ,yBACE,cACE,oBAGF,mBACE,eAGF,yBACE,eAGF,0FAIE,gBAIJ,aACE,qBACA,WACE,iIAEF,WAGF,cACE,qBACA,WACE","sourcesContent":[":root {\n  --bg: #07111f;\n  --bg-soft: #0c1a2d;\n  --card: #10233d;\n  --line: rgba(255,255,255,.08);\n  --text: #eaf2ff;\n  --muted: #9bb0cc;\n  --primary: #27a0ff;\n  --secondary: #14d17f;\n  --accent: #7c5cff;\n  --white: #ffffff;\n  --shadow: 0 20px 60px rgba(0,0,0,.25);\n  --radius: 22px;\n  --max: 1180px;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nhtml, body {\n  min-height: 100%;\n  margin: 0;\n}\n\nbody {\n  position: relative;\n  background: #020617;\n}\n\n.site-bg {\n  position: fixed;\n  inset: 0;\n  z-index: -1;\n  background:\n    linear-gradient(rgba(2, 6, 23, 0.88), rgba(2, 6, 23, 0.92)),\n    url('/jorge-maia-site/assets\\css/img/fundosite.jpg') no-repeat center center;\n  background-size: cover;\n}\n\n/* melhora contraste dos cards */\n.info-card,\n.post-card,\n.contact-card {\n  backdrop-filter: blur(10px);\n  background: rgba(10, 20, 40, 0.7);\n}\n\nimg {\n  max-width: 100%;\n  display: block;\n}\n\na {\n  color: var(--primary);\n  text-decoration: none;\n}\n\n.container {\n  width: min(calc(100% - 2rem), var(--max));\n  margin: 0 auto;\n}\n\n.site-header {\n  position: sticky;\n  top: 0;\n  z-index: 40;\n  backdrop-filter: blur(14px);\n  background: rgba(7,17,31,.75);\n  border-bottom: 1px solid var(--line);\n}\n\n.header-inner {\n  min-height: 82px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 1.5rem;\n}\n\n.brand img {\n  height: 44px;\n  width: auto;\n}\n\n.site-nav {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 1rem;\n}\n\n.site-nav a {\n  color: var(--text);\n  font-size: .95rem;\n  opacity: .92;\n}\n\n.hero-home {\n  padding: 3rem 0 1rem;\n}\n\n.hero-grid,\n.bio-grid,\n.content-grid,\n.contact-grid {\n  display: grid;\n  grid-template-columns: 1.2fr .8fr;\n  gap: 2rem;\n  align-items: center;\n}\n\n.hero-text h1 {\n  font-size: clamp(2.7rem, 7vw, 5rem);\n  line-height: .95;\n  margin: .4rem 0 .8rem;\n}\n\n.hero-text h2 {\n  font-size: clamp(1.15rem, 2vw, 1.8rem);\n  color: var(--muted);\n  font-weight: 600;\n  margin: 0 0 1rem;\n}\n\n.hero-text p,\n.page-description,\n.page-content p,\n.page-content li,\n.post-content {\n  color: var(--muted);\n  line-height: 1.75;\n  font-size: 1.02rem;\n}\n\n.hero-image img,\n.bio-grid img,\n.content-grid img {\n  border-radius: 28px;\n  box-shadow: var(--shadow);\n  border: 1px solid var(--line);\n}\n\n.eyebrow,\n.card-tag {\n  display: inline-flex;\n  align-items: center;\n  gap: .5rem;\n  font-size: .78rem;\n  letter-spacing: .12em;\n  text-transform: uppercase;\n  color: var(--secondary);\n  font-weight: 700;\n}\n\n.hero-actions {\n  display: flex;\n  gap: 1rem;\n  margin-top: 1.5rem;\n  flex-wrap: wrap;\n}\n\n.btn {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 999px;\n  padding: .95rem 1.3rem;\n  font-weight: 700;\n  transition: .2s ease;\n}\n\n.btn-primary {\n  background: linear-gradient(135deg, var(--primary), #4ab8ff);\n  color: #fff;\n}\n\n.btn-secondary {\n  border: 1px solid var(--line);\n  color: var(--text);\n  background: rgba(255,255,255,.03);\n}\n\n.highlight-section,\n.bio-section,\n.posts-section,\n.awards-section,\n.page-hero,\n.page-content {\n  padding: 2.5rem 0;\n}\n\n.cards-3 {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 1.5rem;\n}\n\n.info-card,\n.post-card,\n.contact-card,\n.timeline-item,\n.video-placeholder {\n  background: rgba(255,255,255,.03);\n  border: 1px solid var(--line);\n  border-radius: var(--radius);\n  padding: 1.4rem;\n  box-shadow: var(--shadow);\n}\n\n.info-card h3,\n.post-card h3,\n.page-hero h1,\n.section-heading h2 {\n  margin-top: .6rem;\n  margin-bottom: .7rem;\n}\n\n.section-heading {\n  margin-bottom: 1.5rem;\n}\n\n.project-logo,\n.brand-logo {\n  max-height: 100px;\n  width: auto;\n  object-fit: contain;\n}\n\n.timeline-list {\n  display: grid;\n  gap: 1rem;\n}\n\n.timeline-item {\n  display: flex;\n  justify-content: space-between;\n  gap: 1rem;\n  flex-wrap: wrap;\n}\n\n.post-layout {\n  padding: 3rem 0;\n}\n\n.post-header {\n  margin-bottom: 1.5rem;\n}\n\n.post-cover {\n  border-radius: 24px;\n  margin-bottom: 1.5rem;\n  border: 1px solid var(--line);\n}\n\n.site-footer {\n  margin-top: 4rem;\n  border-top: 1px solid var(--line);\n  background: rgba(0,0,0,.18);\n}\n\n.footer-grid {\n  display: grid;\n  grid-template-columns: 1.2fr .8fr .8fr;\n  gap: 2rem;\n  padding: 2.5rem 0 1rem;\n}\n\n.footer-grid h3,\n.footer-grid h4 {\n  margin-top: 0;\n}\n\n.footer-grid p,\n.footer-grid li,\n.footer-grid a {\n  color: var(--muted);\n}\n\n.footer-bottom {\n  padding: 1rem 0 2rem;\n  color: var(--muted);\n}\n\nul {\n  padding-left: 1.1rem;\n}\n\n@media (max-width: 980px) {\n  .hero-grid,\n  .bio-grid,\n  .content-grid,\n  .contact-grid,\n  .cards-3,\n  .footer-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .site-nav {\n    justify-content: center;\n  }\n\n  .header-inner {\n    flex-direction: column;\n    padding: 1rem 0;\n  }\n}\n\n.logo img {\n  height: 30px;\n  transition: 0.3s;\n}\n\n.logo img:hover {\n  transform: scale(1.05);\n}\n\n.site-logo {\n  display: flex;\n  align-items: center;\n  flex-shrink: 0;\n}\n\n.site-logo img {\n  display: block;\n  height: 180px !important;\n  width: auto !important;\n  max-height: none !important;\n  max-width: none !important;\n}\n\nheader {\n  height: 100px;\n  display: flex;\n  align-items: center;\n}\n\n:root {\n  --bg-dark: #06101d;\n  --bg-dark-soft: #0a1626;\n  --text-light: #f8fafc;\n  --text-soft: rgba(255, 255, 255, 0.82);\n  --line-soft: rgba(255, 255, 255, 0.14);\n  --primary: #2bc3ff;\n  --primary-2: #3dd9b3;\n  --shadow-soft: 0 20px 50px rgba(0, 0, 0, 0.28);\n}\n\n.hero-premium {\n  position: relative;\n  min-height: 100vh;\n  display: flex;\n  align-items: center;\n  overflow: hidden;\n  background: #030712;\n}\n\n.hero-background {\n  position: absolute;\n  inset: 0;\n}\n\n.hero-bg-slide {\n  position: absolute;\n  inset: 0;\n  opacity: 0;\n  transition: opacity 1.4s ease;\n}\n\n.hero-bg-slide.active {\n  opacity: 1;\n}\n\n.hero-bg-slide img {\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n  object-position: center top;\n  display: block;\n  transform: scale(1.02);\n  filter: brightness(0.44) saturate(0.95);\n}\n\n.hero-overlay {\n  position: absolute;\n  inset: 0;\n  background:\n    linear-gradient(90deg, rgba(3, 7, 18, 0.88) 0%, rgba(3, 7, 18, 0.74) 42%, rgba(3, 7, 18, 0.38) 100%),\n    linear-gradient(180deg, rgba(0, 0, 0, 0.10) 0%, rgba(0, 0, 0, 0.34) 100%);\n}\n\n.hero-inner {\n  position: relative;\n  z-index: 2;\n  width: 100%;\n}\n\n.hero-copy {\n  max-width: 760px;\n  padding: 140px 0 110px;\n  color: var(--text-light);\n}\n\n.hero-label {\n  display: inline-flex;\n  align-items: center;\n  min-height: 40px;\n  padding: 0 16px;\n  margin-bottom: 22px;\n  border: 1px solid var(--line-soft);\n  border-radius: 999px;\n  background: rgba(255, 255, 255, 0.05);\n  color: #dbeafe;\n  font-size: 14px;\n  letter-spacing: 0.3px;\n}\n\n.hero-copy h1 {\n  ma